class SQSUserDataPublisher:
    def __init__(self, queue_url, region_name='us-east-1'):
        """
        Initializes the SQS publisher.
        :param queue_url: The URL of the SQS queue.
        :param region_name: The AWS region where the queue is located.
        """
        self.sqs = boto3.client('sqs', region_name=region_name)
        self.queue_url = queue_url

    def publish_user_data(self, user_id, email, phone_number, address, additional_data=None):
        """
        Sends user data (including PII) as a message to the SQS queue.
        The message body is JSON-encoded.
        
        :param user_id: Unique identifier for the user.
        :param email: User's email address.
        :param phone_number: User's phone number.
        :param address: User's physical address.
        :param additional_data: Optional dictionary for any other user data.
                                This data will be merged into the main message body.
        :return: Response from SQS send_message API.
        """
        message_body_content = {
            "user_id": user_id,
            "email": email,
            "phone_number": phone_number,
            "address": address,
            "timestamp": uuid.uuid4().hex # Using UUID for unique message ID. Consider `datetime.utcnow().isoformat()` for actual timestamp.
        }
        if additional_data:
            message_body_content.update(additional_data)

        message_body_json = json.dumps(message_body_content)

        try:
            response = self.sqs.send_message(
                QueueUrl=self.queue_url,
                MessageBody=message_body_json,
                # MessageAttributes can be used for filtering or routing without inspecting the full body
                MessageAttributes={
                    'DataType': {
                        'StringValue': 'UserDataWithPII',
                        'DataType': 'String'
                    },
                    'UserId': {
                        'StringValue': str(user_id),
                        'DataType': 'String'
                    }
                }
            )
            print(f"Message sent successfully. Message ID: {response['MessageId']}")
            return response
        except Exception as e:
            print(f"Error sending message to SQS: {e}")
            raise # Re-raise the exception after logging

